const express = require('express');
const axios = require('axios');

const app = express();
const PORT = 3000;

// Middleware to parse JSON bodies
app.use(express.json());

// POST /verify-license endpoint
app.post('/verify-license', async (req, res) => {
  try {
    const { license_number } = req.body;

    if (!license_number) {
      return res.status(400).json({ error: 'license_number is required' });
    }

    // Call Prembly Driver's License verification API
    const response = await axios.post(
      'https://api.prembly.com/verification/drivers_license',
      { number: license_number },
      {
        headers: {
          'app-id': process.env.PREMBLY_APP_ID,
          'x-api-key': process.env.PREMBLY_API_KEY,
          'Content-Type': 'application/json'
        }
      }
    );

    // Return the verification result to the client
    res.json(response.data);
  } catch (error) {
    console.error('Error verifying license:', error.response ? error.response.data : error.message);

    if (error.response) {
      res.status(error.response.status).json(error.response.data);
    } else {
      res.status(500).json({ error: 'Internal server error' });
    }
  }
});

// Start the server
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

